{/* Theme switcher */}
{(() => {
  const themes = [
    { key:"Indigo Pro", label:"Ivory", desc:"Warm paper", icon:"sun",      paper:"#f6f1e8", ink:"#1a1a1e", accent:"#c46a3a" },
    { key:"Slate Dark", label:"Dark",  desc:"Reduced light", icon:"moon",    paper:"#1a1a1e", ink:"#e8eaed", accent:"#8da4ef" },
    { key:"Mono Clean", label:"Mono",  desc:"High contrast", icon:"contrast", paper:"#f6f6f6", ink:"#0f0f0f", accent:"#0f0f0f" },
  ];
  const current = themes.find(x => x.key === tweaks.theme) || themes[0];
  return (
    <div ref={themeRef} style={{ position:"relative" }}>
      <button onClick={() => setThemeOpen(o => !o)}
        aria-haspopup="listbox" aria-expanded={themeOpen} title={`Theme: ${current.label}`}
        style={{
          width:32, height:32, padding:0,
          background:"transparent", border:`1px solid ${themeOpen ? theme.text+"40" : "transparent"}`,
          borderRadius:"50%", cursor:"pointer",
          display:"inline-flex", alignItems:"center", justifyContent:"center",
          transition:"border-color 0.18s, background 0.18s",
        }}
        onMouseEnter={e => { if (!themeOpen) e.currentTarget.style.background = theme.filterBg; }}
        onMouseLeave={e => e.currentTarget.style.background = "transparent"}>
        <Icon name={current.icon} size={16} color={theme.text}/>
      </button>

      {themeOpen && (
        <div role="listbox" style={{
          position:"absolute", top:"calc(100% + 8px)", right:0,
          width:240, padding:6,
          background: theme.cardBg, border:`1px solid ${theme.cardBorder}`,
          borderRadius:12, boxShadow:"0 14px 40px rgba(0,0,0,0.10), 0 2px 6px rgba(0,0,0,0.04)",
          zIndex:100, animation:"fadeIn 0.14s ease",
        }}>
          <div style={{ padding:"6px 10px 8px", fontSize:10.5, fontWeight:600, color: theme.textMuted, textTransform:"uppercase", letterSpacing:"0.1em" }}>Theme</div>
          {themes.map(th => {
            const active = tweaks.theme === th.key;
            return (
              <button key={th.key} role="option" aria-selected={active}
                onClick={() => { setTweak("theme", th.key); setThemeOpen(false); }}
                style={{
                  width:"100%", display:"flex", alignItems:"center", gap:12,
                  padding:"9px 10px", borderRadius:8, border:"none",
                  background: active ? theme.filterBg : "transparent",
                  cursor:"pointer", textAlign:"left", fontFamily:"inherit",
                  transition:"background 0.12s",
                }}
                onMouseEnter={e => { if (!active) e.currentTarget.style.background = theme.filterBg + "70"; }}
                onMouseLeave={e => { if (!active) e.currentTarget.style.background = "transparent"; }}>
                {/* Theme preview tile */}
                <span style={{
                  width:36, height:26, borderRadius:6, flexShrink:0,
                  background: th.paper,
                  border:`1px solid ${theme.cardBorder}`,
                  position:"relative", overflow:"hidden",
                }}>
                  <span style={{ position:"absolute", top:3, left:3, right:3, height:4, background: th.ink, borderRadius:1.5, opacity:0.9 }}/>
                  <span style={{ position:"absolute", top:10, left:3, width:11, height:4, background: th.accent, borderRadius:1.5 }}/>
                  <span style={{ position:"absolute", top:17, left:3, right:8, height:2.5, background: th.ink, opacity:0.28, borderRadius:1 }}/>
                  <span style={{ position:"absolute", top:21, left:3, right:13, height:2.5, background: th.ink, opacity:0.28, borderRadius:1 }}/>
                </span>
                <span style={{ flex:1, minWidth:0 }}>
                  <span style={{ display:"block", fontSize:13, color: theme.text, fontWeight: active ? 600 : 500, fontFamily:"'Source Serif 4','Source Serif Pro',Georgia,serif", letterSpacing:"-0.01em" }}>{th.label}</span>
                  <span style={{ display:"block", fontSize:11, color: theme.textMuted, marginTop:1 }}>{th.desc}</span>
                </span>
                {active && <Icon name="check" size={13} color={theme.accent}/>}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
})()}

{/* Lang toggle */}
<button onClick={() => setLang(l => l === "en" ? "zh" : "en")} style={{ display:"flex", alignItems:"center", gap:5, background: theme.filterBg, border:`1px solid ${theme.cardBorder}`, color: theme.text, cursor:"pointer", padding:"5px 10px", borderRadius:7, fontSize:12, fontWeight:600, fontFamily:"inherit" }}>
  <Icon name="globe" size={13} color={theme.textMuted}/>
  {lang === "en" ? "中文" : "EN"}
</button>

{/* User avatar */}
<button onClick={() => { setProfileOpen(true); setPublishOpen(false); setActiveExtId(null); }}
  title={t.profile_title}
  style={{ width:32, height:32, borderRadius:"50%", background: profileOpen ? theme.accent : `${theme.accent}22`, display:"flex", alignItems:"center", justifyContent:"center", cursor:"pointer", border:`1.5px solid ${profileOpen ? theme.accent : theme.accent+"40"}`, padding:0, transition:"all 0.15s" }}>
  <Icon name="user" size={15} color={profileOpen ? "#fff" : theme.accent}/>
</button>

