  --color-status-released:    oklch(72% 0.14 155);
  --color-status-released-bg: oklch(22% 0.04 155);
  --color-status-dev:         oklch(78% 0.14 65);
  --color-status-dev-bg:      oklch(22% 0.04 65);
  --color-status-none:        oklch(70% 0.012 240);
  --color-status-none-bg:     oklch(20% 0.008 240);
  --color-layer-industry:     oklch(75% 0.12 240);
  --color-layer-industry-bg:  oklch(22% 0.04 240);
  --color-layer-public:       oklch(72% 0.18 200);
  --color-layer-public-bg:    oklch(22% 0.04 70);
}

@layer components {
  .badge-official { background: oklch(94% 0.025 70); color: oklch(35% 0.07 35); }
  .badge-popular  { background: oklch(94% 0.04 145); color: oklch(35% 0.12 145); }
  .badge-new      { background: oklch(95% 0.035 90); color: oklch(38% 0.13 70); }
  .dark .badge-official { background: oklch(22% 0.06 200); color: oklch(72% 0.18 200); }
  .dark .badge-popular  { background: oklch(22% 0.05 280); color: oklch(72% 0.16 280); }
  .dark .badge-new      { background: oklch(22% 0.05 50);  color: oklch(78% 0.16 50); }
}

